const GraphResource = struct {
    graph: ArrayGraph(void, f64),
};

pub const GraphRes = beam.Resource(GraphResource, @import("root"), .{
    .Callbacks = struct {
        pub fn dtor(ptr: *GraphResource) void {
            ptr.graph.deinit();
