pub fn nif_density(res: GraphRes) !f64 {
    const g = res.unpack().graph;
    const n = g.nodeCapacity();
    if (n <= 1) return 0.0;
    const possible_edges = @as(f64, @floatFromInt(n * (n - 1)));
    return @as(f64, @floatFromInt(g.edgeCount())) / possible_edges;
}

